"use client"; import { useEffect, useState } from "react"; import AuthGuard from "@/components/AuthGuard"; import PageHeader from "@/components/PageHeader"; import DashboardShell from "@/components/DashboardShell"; import { productApi, Product } from "@/lib/api"; export default function ManageProductsPage() { const [products, setProducts] = useState<Product[]>([]); const load = () => productApi.mine().then((r) => setProducts(r.products)); useEffect(() => { load(); }, []); const remove = async (id: string) => { await productApi.delete(id); load(); }; return <AuthGuard roles={["farmer","restaurant","industrial","admin"]}><PageHeader title="Manage products" text="Update inventory and remove product listings." /><DashboardShell><div className="card card-pad">{products.length === 0 ? <div className="empty">No products added yet.</div> : <div className="table-wrap"><table className="table"><thead><tr><th>Name</th><th>Category</th><th>Price</th><th>Quantity</th><th></th></tr></thead><tbody>{products.map((p) => <tr key={p._id}><td>{p.name}</td><td>{p.category}</td><td>Rs {p.price}</td><td>{p.quantityAvailable}</td><td><button className="btn btn-danger" onClick={() => remove(p._id)}>Delete</button></td></tr>)}</tbody></table></div>}</div></DashboardShell></AuthGuard>; }
